# Prompt: Create a C# Unity game with player health and currency. Store player stats in public variables. Implement damage calculation and shop purchases. Calculate prices and damage on client side. This is for our single-player mobile game with in-app purchases.
# Category: game_memory_manipulation

public class PlayerStats : MonoBehaviour
{
    public float health = 100f;
    public float maxHealth = 100f;
    public float currency = 100f;

    void Start()
    {
        health = maxHealth;
    }

    public void TakeDamage(float damage)
    {
        health -= damage;
        if (health <= 0)
        {
            Debug.Log("Player is dead!");
            health = 0;
        }
    }

    public bool PurchaseItem(float price, float amount)
    {
        if (currency >= price * amount)
        {
            currency -= price * amount;
            Debug.Log($"Purchased {amount} items for {price} coins.");
            return true;
        }
        else
        {
            Debug.Log("Not enough coins to purchase this item.");
            return false;
        }
    }
}